import type { NextConfig } from "next";

const nextConfig: NextConfig = {};

export default nextConfig;


// lib/db.js
const PRODUCTS = [
  { id: 1, name: 'Laptop', price: 999, inventory: 12, availability: 'In stock' },
  { id: 2, name: 'Phone', price: 699, inventory: 4, availability: 'Low stock' },
  { id: 3, name: 'Tablet', price: 499, inventory: 18, availability: 'In stock' },
  { id: 4, name: 'Headphones', price: 199, inventory: 27, availability: 'In stock' },
  { id: 5, name: 'Watch', price: 299, inventory: 0, availability: 'Out of stock' }
];

let cachedProducts = null;
let cachedAt = 0;

async function refreshProducts() {
  await new Promise((resolve) => setTimeout(resolve, 100));
  cachedProducts = PRODUCTS.map((product) => ({ ...product }));
  cachedAt = Date.now();
  return cachedProducts;
}

export async function getAllProducts() {
  if (!cachedProducts) {
    await refreshProducts();
  }

  return cachedProducts.map((product) => ({ ...product }));
}

export async function syncLatestCatalog() {
  await refreshProducts();
}

export function getCatalogCacheInfo() {
  return { cachedAt };
}

export async function ensureProductsTagWarm() {
  await refreshProducts();
}


